import style from './Portofolio.module.css'
import { Link } from 'react-router-dom';

function Portofolio() {

    const projects = [
        {
            id: 1,
            title: "Animated Landing Page",
            description: "Creative landing page with smooth animations.",
            image: "/image/project1.gif",
        },
        {
            id: 2,
            title: "E-Commerce Website",
            description: "Responsive online store with React & Node.js.",
            image: "/image/project2.jpg",
        },
        {
            id: 3,
            title: "Portfolio Website",
            description: "Personal portfolio with modern UI design.",
            image: "/image/project3.png",
        },
    ];


    return (
        <div className={style.portofoliopage}>
            <header className={style.header}>
                <h1 className={style.logo}>MSHDQ</h1>
                <nav className={style.nav}>
                    <Link to="/" className={style.link}>HOME</Link>
                    <Link to="/about" className={style.link}>ABOUT</Link>
                    <Link to="/service" className={style.link}>SERVICE</Link>
                    <Link to="/portofolio" className={style.link}>PORTOFOLIO</Link>
                    <Link to="/blog" className={style.link}>BLOG</Link>
                    <Link to="/contact" className={style.link}>CONTACT</Link>
                </nav>
            </header>
            
            <div className="portfolio">
                <h1 className="portfolio-title">My Portfolio</h1>
                <p className="portfolio-subtitle">
                    Some of my works — including GIF demos and screenshots.
                </p>

                <div className="portfolio-grid">
                    {projects.map((project) => (
                        <div className="portfolio-card" key={project.id}>
                            <img
                                src={project.image}
                                alt={project.title}
                                className="portfolio-image"
                            />
                            <h2 className="portfolio-card-title">{project.title}</h2>
                            <p className="portfolio-card-desc">{project.description}</p>
                        </div>
                    ))}
                </div>
            </div>

        </div>
    )
}

export default Portofolio;
